import {FaInstagram,FaLinkedin,FaGithub} from 'react-icons/fa';export default function SocialLinks({links,theme='light'}){const cls=theme==='dark'?'card dark p-3 social text-center':'card light p-3 social text-center';const icons={Instagram:<FaInstagram/>,LinkedIn:<FaLinkedin/>,GitHub:<FaGithub/>};return <div className={cls}><h4>Social Links</h4>{links.map((l,i)=><a key={i} href={l.url} target='_blank' rel='noreferrer'>{icons[l.name]} {l.name}</a>)}</div>}